#include <vector>
#include <string>
#include <algorithm>
#include <cmath>

/**
 * @brief Counts the total occurrences of a specific digit in all numbers of an array.
 * 
 * @param nums The array of integers.
 * @param digit The digit to count.
 * @return long long The total count of the digit.
 */
long long solve(std::vector<long long> nums, long long digit) {
    long long total_count = 0;
    char target_char = digit + '0';

    for (long long num : nums) {
        // Convert the number to a string to easily count digits
        std::string s = std::to_string(num);

        // Count the occurrences of the target digit character in the string
        for (char c : s) {
            if (c == target_char) {
                total_count++;
            }
        }
    }
    return total_count;
}
